import{_ as t,c as s,o as a,a1 as n}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"上下文注入: Agent 自動記憶 | opencode-supermemory","description":"學習 opencode-supermemory 的自動上下文注入機制。了解 Agent 如何在會話開始時獲取使用者設定檔和專案知識，掌握關鍵詞觸發記憶儲存的方法。","frontmatter":{"title":"上下文注入: Agent 自動記憶 | opencode-supermemory","sidebarTitle":"上下文注入","subtitle":"自動上下文注入機制：讓 Agent \\"未卜先知\\"","description":"學習 opencode-supermemory 的自動上下文注入機制。了解 Agent 如何在會話開始時獲取使用者設定檔和專案知識，掌握關鍵詞觸發記憶儲存的方法。","tags":["context","injection","prompt","memory"],"prerequisite":["start-getting-started"],"order":1},"headers":[],"relativePath":"zh-tw/supermemoryai/opencode-supermemory/core/context-injection/index.md","filePath":"zh-tw/supermemoryai/opencode-supermemory/core/context-injection/index.md"}'),o={name:"zh-tw/supermemoryai/opencode-supermemory/core/context-injection/index.md"};function i(r,e,l,p,d,c){return a(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="自動上下文注入機制-讓-agent-未卜先知" tabindex="-1">自動上下文注入機制：讓 Agent &quot;未卜先知&quot; <a class="header-anchor" href="#自動上下文注入機制-讓-agent-未卜先知" aria-label="Permalink to &quot;自動上下文注入機制：讓 Agent &quot;未卜先知&quot;&quot;">​</a></h1><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><p>學完本課，你將能夠：</p><ol><li><strong>理解</strong> 為什麼 Agent 一上來就知道你的編碼習慣和專案架構。</li><li><strong>掌握</strong> 上下文注入的「三維模型」（使用者設定檔、專案知識、相關記憶）。</li><li><strong>學會</strong> 使用關鍵詞（如 &quot;Remember this&quot;）主動干預 Agent 的記憶行為。</li><li><strong>配置</strong> 注入的條目數量，平衡上下文長度與資訊豐富度。</li></ol><hr><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>在沒有記憶外掛之前，每次開啟新會話，Agent 都是一張白紙。你必須重複告訴它：「我是用 TypeScript 的」、「這個專案用的是 Next.js」。</p><p><strong>上下文注入（Context Injection）</strong> 解決了這個問題。它就像在 Agent 醒來的一瞬間，把一份「任務簡報」塞進它的腦子裡。</p><h3 id="觸發時機" tabindex="-1">觸發時機 <a class="header-anchor" href="#觸發時機" aria-label="Permalink to &quot;觸發時機&quot;">​</a></h3><p>opencode-supermemory 極其克制，只在 <strong>會話的第一條訊息</strong> 時觸發自動注入。</p><ul><li><strong>為什麼是第一條？</strong> 因為這是確立會話基調的關鍵時刻。</li><li><strong>後續訊息呢？</strong> 後續訊息不再自動注入，以免干擾對話流程，除非你主動觸發（見下文「關鍵詞觸發」）。</li></ul><h3 id="三維注入模型" tabindex="-1">三維注入模型 <a class="header-anchor" href="#三維注入模型" aria-label="Permalink to &quot;三維注入模型&quot;">​</a></h3><p>外掛會並行獲取三類資料，組合成一個 <code>[SUPERMEMORY]</code> 提示區塊：</p><table tabindex="0"><thead><tr><th>資料維度</th><th>來源</th><th>作用</th><th>範例</th></tr></thead><tbody><tr><td><strong>1. 使用者設定檔</strong> (Profile)</td><td><code>getProfile</code></td><td>你的長期偏好</td><td>&quot;使用者喜歡函數式程式設計&quot;、&quot;偏好箭頭函數&quot;</td></tr><tr><td><strong>2. 專案知識</strong> (Project)</td><td><code>listMemories</code></td><td>當前專案的全面知識</td><td>&quot;本專案使用 Clean Architecture&quot;、&quot;API 放在 src/api&quot;</td></tr><tr><td><strong>3. 相關記憶</strong> (Relevant)</td><td><code>searchMemories</code></td><td>與你第一句話相關的過往經驗</td><td>你問「怎麼修這個 Bug」，它搜出之前的類似修復記錄</td></tr></tbody></table><hr><h2 id="注入了什麼" tabindex="-1">注入了什麼？ <a class="header-anchor" href="#注入了什麼" aria-label="Permalink to &quot;注入了什麼？&quot;">​</a></h2><p>當你在 OpenCode 中發送第一條訊息時，外掛會在背景默默將以下內容插入到 System Prompt 中。</p><details class="details custom-block"><summary>點擊查看注入內容的真實結構</summary><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[SUPERMEMORY]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User Profile:</span></span>
<span class="line"><span>- User prefers concise responses</span></span>
<span class="line"><span>- User uses Zod for all validations</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Recent Context:</span></span>
<span class="line"><span>- Working on auth module refactoring</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Project Knowledge:</span></span>
<span class="line"><span>- [100%] Architecture follows MVC pattern</span></span>
<span class="line"><span>- [100%] Use &#39;npm run test&#39; for testing</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Relevant Memories:</span></span>
<span class="line"><span>- [85%] Previous fix for hydration error: use useEffect</span></span></code></pre></div></details><p>Agent 看到這些資訊後，就會表現得像一個在這個專案工作了很久的老員工，而不是新來的實習生。</p><hr><h2 id="關鍵詞觸發機制-nudge" tabindex="-1">關鍵詞觸發機制 (Nudge) <a class="header-anchor" href="#關鍵詞觸發機制-nudge" aria-label="Permalink to &quot;關鍵詞觸發機制 (Nudge)&quot;">​</a></h2><p>除了開頭的自動注入，你還可以在對話過程中隨時「喚醒」記憶功能。</p><p>外掛內建了一個 <strong>關鍵詞偵測器</strong>。只要你的訊息中包含特定的觸發詞，外掛會向 Agent 發送一個「隱形提示」（Nudge），強制它呼叫儲存工具。</p><h3 id="預設觸發詞" tabindex="-1">預設觸發詞 <a class="header-anchor" href="#預設觸發詞" aria-label="Permalink to &quot;預設觸發詞&quot;">​</a></h3><ul><li><code>remember</code></li><li><code>save this</code></li><li><code>don&#39;t forget</code></li><li><code>memorize</code></li><li><code>take note</code></li><li>... (更多見原始碼配置)</li></ul><h3 id="互動範例" tabindex="-1">互動範例 <a class="header-anchor" href="#互動範例" aria-label="Permalink to &quot;互動範例&quot;">​</a></h3><p><strong>你輸入</strong>：</p><blockquote><p>這裡的 API 回應格式變了，<strong>remember</strong> 以後都用 <code>data.result</code> 而不是 <code>data.payload</code>。</p></blockquote><p><strong>外掛偵測到 &quot;remember&quot;</strong>：</p><blockquote><p>（背景注入提示）：<code>[MEMORY TRIGGER DETECTED] The user wants you to remember something...</code></p></blockquote><p><strong>Agent 反應</strong>：</p><blockquote><p>收到。我會記住這個變更。 <em>(背景呼叫 <code>supermemory.add</code> 儲存記憶)</em></p></blockquote><hr><h2 id="深度配置" tabindex="-1">深度配置 <a class="header-anchor" href="#深度配置" aria-label="Permalink to &quot;深度配置&quot;">​</a></h2><p>你可以透過修改 <code>~/.config/opencode/supermemory.jsonc</code> 來調整注入行為。</p><h3 id="常用配置項" tabindex="-1">常用配置項 <a class="header-anchor" href="#常用配置項" aria-label="Permalink to &quot;常用配置項&quot;">​</a></h3><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 是否注入使用者設定檔（預設 true）</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;injectProfile&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 每次注入多少條專案記憶（預設 10）</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 調大能讓 Agent 更了解專案，但會消耗更多 Token</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;maxProjectMemories&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 每次注入多少條使用者設定檔條目（預設 5）</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;maxProfileItems&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 自訂觸發詞（支援正則）</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;keywordPatterns&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;記一下&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;永久儲存&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">提示</p><p>配置修改後，需要重新啟動 OpenCode 或重新載入外掛才能生效。</p></div><hr><h2 id="常見問題" tabindex="-1">常見問題 <a class="header-anchor" href="#常見問題" aria-label="Permalink to &quot;常見問題&quot;">​</a></h2><h3 id="q-注入的資訊會佔用很多-token-嗎" tabindex="-1">Q: 注入的資訊會佔用很多 Token 嗎？ <a class="header-anchor" href="#q-注入的資訊會佔用很多-token-嗎" aria-label="Permalink to &quot;Q: 注入的資訊會佔用很多 Token 嗎？&quot;">​</a></h3><p><strong>A</strong>: 會佔用一部分，但通常可控。預設配置下（10條專案記憶 + 5條設定檔），大約佔用 500-1000 Token。對於現代大型模型（如 Claude 3.5 Sonnet）的 200k 上下文來說，這只是九牛一毛。</p><h3 id="q-為什麼我說了-remember-它沒反應" tabindex="-1">Q: 為什麼我說了 &quot;remember&quot; 它沒反應？ <a class="header-anchor" href="#q-為什麼我說了-remember-它沒反應" aria-label="Permalink to &quot;Q: 為什麼我說了 &quot;remember&quot; 它沒反應？&quot;">​</a></h3><p><strong>A</strong>:</p><ol><li>檢查是否拼寫正確（支援正則匹配）。</li><li>確認 API Key 是否配置正確（如果外掛未初始化，不會觸發）。</li><li>Agent 可能決定忽略（雖然外掛強制提示了，但 Agent 有最終決定權）。</li></ol><h3 id="q-相關記憶-是怎麼搜出來的" tabindex="-1">Q: &quot;相關記憶&quot; 是怎麼搜出來的？ <a class="header-anchor" href="#q-相關記憶-是怎麼搜出來的" aria-label="Permalink to &quot;Q: &quot;相關記憶&quot; 是怎麼搜出來的？&quot;">​</a></h3><p><strong>A</strong>: 它是基於你 <strong>第一條訊息的內容</strong> 進行語意搜尋的。如果你第一句話只說了 &quot;Hi&quot;，可能搜不出什麼有用的相關記憶，但「專案知識」和「使用者設定檔」依然會被注入。</p><hr><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><ul><li><strong>自動注入</strong> 僅在會話第一條訊息觸發。</li><li><strong>三維模型</strong> 包含使用者設定檔、專案知識和相關記憶。</li><li><strong>關鍵詞觸發</strong> 讓你可以隨時命令 Agent 儲存記憶。</li><li>透過 <strong>配置檔案</strong> 可以控制注入的資訊量。</li></ul><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們學習 <strong><a href="./../tools/">工具集詳解：教 Agent 記憶</a></strong>。</p><p>你會學到：</p><ul><li>如何手動使用 <code>add</code>、<code>search</code> 等工具。</li><li>如何查看和刪除錯誤的記憶。</li></ul></blockquote><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>注入觸發邏輯</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L125-L176" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>125-176</td></tr><tr><td>關鍵詞偵測</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L34-L37" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>34-37</td></tr><tr><td>Prompt 格式化</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/services/context.ts#L14-L64" target="_blank" rel="noreferrer"><code>src/services/context.ts</code></a></td><td>14-64</td></tr><tr><td>預設配置</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/config.ts#L44-L54" target="_blank" rel="noreferrer"><code>src/config.ts</code></a></td><td>44-54</td></tr></tbody></table><p><strong>關鍵函數</strong>：</p><ul><li><code>formatContextForPrompt()</code>: 組裝 <code>[SUPERMEMORY]</code> 文字區塊。</li><li><code>detectMemoryKeyword()</code>: 正則匹配使用者訊息中的觸發詞。</li></ul></details><h2 id="下一課預告-1" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告-1" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們學習 <strong><a href="./../tools/">工具集詳解：教 Agent 記憶</a></strong>。</p><p>你會學到：</p><ul><li>掌握 <code>add</code>, <code>search</code>, <code>profile</code> 等 5 種核心工具模式</li><li>如何手動干預和修正 Agent 的記憶</li><li>使用自然語言觸發記憶儲存</li></ul></blockquote>`,57)])])}const g=t(o,[["render",i]]);export{u as __pageData,g as default};
